import{_ as t,o as a,c as e,a4 as s}from"./chunks/framework.Bz0lZ1uX.js";const g=JSON.parse('{"title":"中村修二 - 蓝色LED之父","description":"","frontmatter":{},"headers":[],"relativePath":"materials/人物素材/中村修二.md","filePath":"materials/人物素材/中村修二.md","lastUpdated":null}'),l={name:"materials/人物素材/中村修二.md"},r=s('<h1 id="中村修二-蓝色led之父" tabindex="-1">中村修二 - 蓝色LED之父 <a class="header-anchor" href="#中村修二-蓝色led之父" aria-label="Permalink to &quot;中村修二 - 蓝色LED之父&quot;">​</a></h1><p><strong>标签</strong>: #科学家 #诺贝尔奖 #坚持不懈 #专注 #科技报国 #平凡中的伟大</p><hr><h2 id="核心事迹简介" tabindex="-1">核心事迹简介 <a class="header-anchor" href="#核心事迹简介" aria-label="Permalink to &quot;核心事迹简介&quot;">​</a></h2><p>中村修二，日裔美籍电子工程学家，曾默默无闻地在小型化学公司研究发光二极管。他凭借近乎偏执的坚持，在众人不看好的氮化镓技术路线上独自攻坚，最终研制出高亮度蓝色LED，补全了照明三原色，荣获2014年诺贝尔物理学奖，用一束蓝光照亮了整个节能时代。</p><hr><h2 id="考场议论文论证片段" tabindex="-1">考场议论文论证片段 <a class="header-anchor" href="#考场议论文论证片段" aria-label="Permalink to &quot;考场议论文论证片段&quot;">​</a></h2><h3 id="片段1-个人品质角度" tabindex="-1">片段1（个人品质角度） <a class="header-anchor" href="#片段1-个人品质角度" aria-label="Permalink to &quot;片段1（个人品质角度）&quot;">​</a></h3><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>坚持，往往意味着在无人问津的黑暗中独自掘进。当中村修二决定攻克蓝色LED难题时，整个学界都认为氮化镓技术毫无希望，他所在的小公司也无力提供高端设备。然而他没有被外界的质疑和条件的简陋所击垮，反而将简陋的实验室当作自己的战场，数千次试验，无数次失败，终于从氮化镓中唤醒了那抹沉睡的蓝光。正是这种不计得失的执着，让看似不可能的梦想照进现实。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="片段2-时代价值角度" tabindex="-1">片段2（时代价值角度） <a class="header-anchor" href="#片段2-时代价值角度" aria-label="Permalink to &quot;片段2（时代价值角度）&quot;">​</a></h3><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>一项技术的突破，往往能撬动整个时代的变革。在中村修二之前，世界只有红光与绿光LED，无法合成照亮黑夜的白光。他的蓝色LED不仅补全了色彩拼图，更催生了高效节能的白色照明，让数十亿人用上了更便宜、更环保的光源。从家庭灯泡到城市大屏，从手机背光到医疗设备，这束蓝光无声地融入现代生活的每个角落。中村修二的贡献早已超越个人荣誉，成为人类迈向可持续未来的重要基石。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><hr><h2 id="适用高考作文主题" tabindex="-1">适用高考作文主题 <a class="header-anchor" href="#适用高考作文主题" aria-label="Permalink to &quot;适用高考作文主题&quot;">​</a></h2><p>坚持 · 创新 · 专注 · 科技报国 · 平凡中的伟大</p><hr><h2 id="高中作文写作建议" tabindex="-1">高中作文写作建议 <a class="header-anchor" href="#高中作文写作建议" aria-label="Permalink to &quot;高中作文写作建议&quot;">​</a></h2><table><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">具体建议</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>段落位置</strong></td><td style="text-align:left;">建议用于文章第三段作为核心论据，或与爱迪生、诺贝尔等发明家形成对比论证</td></tr><tr><td style="text-align:left;"><strong>过渡句式</strong></td><td style="text-align:left;">&quot;如果说前人的成就是站在巨人的肩膀上，那么中村修二则用行动证明，巨人往往诞生于孤独的跋涉中&quot;</td></tr><tr><td style="text-align:left;"><strong>扣题方法</strong></td><td style="text-align:left;">叙述事例后，务必用&quot;正是这份……，使他……&quot;的句式将人物品质与主题词紧密勾连</td></tr><tr><td style="text-align:left;"><strong>立意升格</strong></td><td style="text-align:left;">可将其与&quot;科技自立&quot;&quot;中国芯片突围&quot;等时代命题结合，从个人奋斗上升到国家创新战略高度</td></tr></tbody></table>',17),n=[r];function i(o,d,h,c,p,u){return a(),e("div",null,n)}const m=t(l,[["render",i]]);export{g as __pageData,m as default};
